import React, { useState, useEffect, useRef } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../App';

export default function Navbar() {
  const { user, logout } = useAuth();
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);
  const navigate = useNavigate();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 8);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    const handleClick = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  // Close mobile menu on navigation
  useEffect(() => { setMobileOpen(false); }, [navigate]);

  const handleLogout = () => {
    logout();
    setDropdownOpen(false);
    navigate('/');
  };

  const initials = user
    ? (user.firstName?.[0] || '') + (user.lastName?.[0] || '')
    : '';

  return (
    <>
      <nav className={`navbar${scrolled ? ' scrolled' : ''}`} aria-label="Main navigation">
        <div className="container">
          <Link to="/" className="nav-brand" aria-label="FOSSEE Workshops home">
            <span className="nav-brand-dot" aria-hidden="true"></span>
            FOSSEE Workshops
          </Link>

          {/* Desktop nav */}
          <ul className="nav-links" role="list">
            <li><NavLink to="/">Home</NavLink></li>
            <li><NavLink to="/workshop-types">Workshop Types</NavLink></li>
            {user && (
              <>
                <li><NavLink to="/my-workshops">My Workshops</NavLink></li>
                <li><NavLink to="/propose">Propose</NavLink></li>
              </>
            )}
          </ul>

          <div className="nav-actions">
            {user ? (
              <div className="nav-avatar" ref={dropdownRef}>
                <button
                  className="nav-avatar-btn"
                  onClick={() => setDropdownOpen(!dropdownOpen)}
                  aria-haspopup="true"
                  aria-expanded={dropdownOpen}
                  aria-label="User menu"
                >
                  <span className="avatar-circle" aria-hidden="true">
                    {initials || '?'}
                  </span>
                  {user.firstName}
                  <svg width="12" height="12" viewBox="0 0 12 12" fill="none" aria-hidden="true">
                    <path d="M3 4.5L6 7.5L9 4.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </button>
                {dropdownOpen && (
                  <div className="dropdown-menu" role="menu">
                    <Link className="dropdown-item" to="/profile" role="menuitem" onClick={() => setDropdownOpen(false)}>
                      Profile
                    </Link>
                    <hr className="dropdown-divider" />
                    <button className="dropdown-item" onClick={handleLogout} role="menuitem">
                      Sign out
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <>
                <Link to="/login" className="btn btn-ghost btn-sm">Sign in</Link>
                <Link to="/register" className="btn btn-primary btn-sm">Register</Link>
              </>
            )}

            {/* Hamburger */}
            <button
              className={`hamburger${mobileOpen ? ' open' : ''}`}
              onClick={() => setMobileOpen(!mobileOpen)}
              aria-label={mobileOpen ? 'Close menu' : 'Open menu'}
              aria-expanded={mobileOpen}
              aria-controls="mobile-menu"
            >
              <span aria-hidden="true"></span>
              <span aria-hidden="true"></span>
              <span aria-hidden="true"></span>
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile menu */}
      {mobileOpen && (
        <nav id="mobile-menu" className="mobile-menu" aria-label="Mobile navigation">
          <ul className="mobile-nav-links" role="list">
            <li><Link to="/" onClick={() => setMobileOpen(false)}>🏠 Home</Link></li>
            <li><Link to="/workshop-types" onClick={() => setMobileOpen(false)}>📚 Workshop Types</Link></li>
            {user && (
              <>
                <li><Link to="/my-workshops" onClick={() => setMobileOpen(false)}>📋 My Workshops</Link></li>
                <li><Link to="/propose" onClick={() => setMobileOpen(false)}>✏️ Propose Workshop</Link></li>
                <li><Link to="/profile" onClick={() => setMobileOpen(false)}>👤 Profile</Link></li>
              </>
            )}
          </ul>
          <hr className="mobile-divider" />
          {user ? (
            <button className="btn btn-outline" style={{width:'100%'}} onClick={handleLogout}>
              Sign out
            </button>
          ) : (
            <div style={{display:'flex', gap:'10px', flexDirection:'column'}}>
              <Link to="/login" className="btn btn-outline" onClick={() => setMobileOpen(false)} style={{justifyContent:'center'}}>
                Sign in
              </Link>
              <Link to="/register" className="btn btn-primary" onClick={() => setMobileOpen(false)} style={{justifyContent:'center'}}>
                Create account
              </Link>
            </div>
          )}
        </nav>
      )}
    </>
  );
}
